import{_ as a,o as t,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const P=JSON.parse('{"title":"精血御剑术","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/精血御剑术.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/精血御剑术.md"}'),o={name:"4.资源分区/6.技艺及称号/武技类/白刃类/精血御剑术.md"};function d(_,r,l,b,i,c){return t(),p("div",null,[...r[0]||(r[0]=[e("h1",{id:"精血御剑术",tabindex:"-1"},[n("精血御剑术 "),e("a",{class:"header-anchor",href:"#精血御剑术","aria-label":'Permalink to "精血御剑术"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌037")])])],-1),s('<h1 id="精血御剑术-1" tabindex="-1">精血御剑术 <a class="header-anchor" href="#精血御剑术-1" aria-label="Permalink to &quot;精血御剑术&quot;">​</a></h1><p>精血御剑术<br> 价格：D+500<br> 描述：这是一门古老的剑修秘法——精血养剑之术。此法不假外物，不求天地灵气，独以剑修自身心头精血为引，日夜浇灌、心神祭炼，从而凝练出对应天地二十四节气的二十四柄本命节气剑。<br> 效果：使用【节气剑】进行的攻击被称为【御剑】，【御剑】是一个标准动作，在这次攻击中无法附带任何招式，攻击使用【决心属性+武技+专业：剑+专业：弹道学+武器伤害+其他加值（若有）】，视为远程白刃类攻击，基础射程：15+传奇操纵*5米。</p><p>特殊的是，你每获得一柄【节气剑】皆需浇灌精血，这会使你在购买每一柄节气剑后失去1点生命值上限，但相应的会使你在【御剑】进行的相关行为时，使【节气剑】获得【法破】【回力】特性。</p><p>在没有获得相应能力前，你只能将一把【节气】作为武器计入【御剑】攻击中，【御剑】攻击中若要计入武器，则只能使用【节气剑】，操纵【节气剑】进行【御剑】攻击会正常占用你的手持武器位置。</p><p>若在没有使用【节气剑】的情况下，【御剑】攻击表现为发出一道气剑，武器伤害0L，伤害类型为物理-挥砍。</p><p>研发（10XP）：购买该研发如同购买一项D级技艺一样处理，正常提供自由属性；研发后，你无需承受因为二十四节气剑浇灌精血导致的生命值上限降低效果（向前追溯，向后生效，因此已经降低的生命值上限也会恢复）。</p><p>研发（10XP）：购买该研发如同购买一项D级技艺一样处理，正常提供自由属性；研发后，你可以同时操纵所有【节气剑】进行格挡，这会使你在格挡防御额外提升等同【节气剑】数量*1点；因此获得的额外格挡防御，在购买任意一项节气剑C级技艺研发后将会被动生效，而无需主动格挡才会生效。</p><p>研发（20XP）：购买该研发如同购买一项C级技艺一样处理，正常提供自由属性；研发后你可以将购买的每把【节气剑】计入【御剑】攻击中，但只有你选择的一件【节气剑】正常生效，其他【节气剑】每有一件就会为【御剑】攻击提供1DP器械加值并额外造成1点多次攻击减值；【御剑】攻击的射程提升至20+传奇操纵*5米。</p><p>研发（40XP）：你需要具有二十四节气剑下属所有研发后才能购买这一研发，如同购买一项B级技艺一样处理，正常提供自由属性；【御剑】攻击的基础射程改为15+操纵*5米，可以同时对射程内的所有敌对单位进行攻击，可以使目标使用反射豁免而非正常防御，同时【御剑】攻击具有【幻灭】特性。</p><p>【精血御剑术下属技艺】<br> 灵窍<br> 价格：D+500+1XP<br> 描述：君子藏器于身，待时而动。<br> 效果：你在穴窍中开辟了一个特殊的储物空间，这一储物空间只能用来储存【节气剑】；放入/取出【节气剑】是一个迅捷动作，可以正常被降低取出武器动作的能力所降低取出动作。</p><p>精血养剑<br> 价格：D+500+2XP.<br> 描述：以精血进一步温养节气剑，从而在使用起来减少心力消耗。<br> 效果：每轮一次，当你使用节气剑的效果时，若需要消费意志力，则减少1点意志力消耗（可减少至0）。</p><p>本命飞剑<br> 价格：C+2000+4XP<br> 描述：将精血灌溉的节气剑化作本命飞剑，通过不断磨合进一步提升契合度，从而减轻操纵负担，在御剑时灵活的调用更多飞剑进行战斗。<br> 效果：当你使用【节气剑】进行【御剑】攻击时，你可以额外将一把【节气剑】视同手持并将其的一半武器伤害与所有特性加入攻击中；你每经历一场影片，就可以额外多将一把【节气剑】视同手持并将一半武器伤害与所有特性加入攻击中，你至多以此方式额外将传奇决心-1柄【节气剑】视作手持并加入攻击。 你依旧需要选择一件【节气剑】作为完整计入的武器，并采用这一【节气剑】的伤害类型作为攻击伤害类型。以此进行的【御剑】，在表现上为多把节气剑悬浮在空中，环绕你的四周，并一齐发动攻击。</p><p>特殊的是，以这种方式计入攻击的节气剑会正常承受肢体妨碍不良点数造成的减值或严重等后果的影响。<br> 这意味着承受一档肢体妨碍不良点数时目标可以指定你的一把节气剑造成肢体妨碍不良点数，从而使你在计入那把节气剑的御剑攻击时，正常承受相应减值或后果（你也可以选择在攻击时不计入）。一旦承受二档肢体妨碍不良点数，会导致所有本命剑都会和肢体一样承受相应的不良点数，移除与治疗方式等同正常肢体，这是因为本命剑与你联系过深，冥冥之中受到的反馈的影响。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',15)])])}const f=a(o,[["render",d]]);export{P as __pageData,f as default};
